// Animation-lifecycle helper for the LifeShooter game loop, extracted as a pure
// predicate so the post-death stop condition is unit-testable (the component's rAF
// loop itself can't be). After the ship burns, the loop keeps drawing for a short
// linger — the fire fades behind the translucent game-over overlay — then ceases.
// Without this the Game-of-Life sim ran on every animation frame forever and pegged
// the CPU on the game-over screen. See lifeShooterLoop.test.ts.

// How long the fire keeps burning after death before the loop stops scheduling frames.
export const DEATH_LINGER_MS = 3000

// Whether the rAF loop should schedule another frame. While the ship is alive it
// always continues; once dead (deadAt = the timestamp the loop first observed death)
// it continues only until the linger elapses, then returns false so the caller stops
// rescheduling. deadAt is only meaningful when dead is true (the caller stamps it on
// the first dead frame).
export const shouldKeepAnimating = (dead: boolean, deadAt: number, now: number): boolean =>
  !dead || now - deadAt < DEATH_LINGER_MS

// Whether a running loop is still the one allowed to run. Each effect invocation
// claims a fresh identity (`mine`) as the module-level current one; a loop runs only
// if it still holds the current identity and cleanup hasn't stopped it. Compared with
// `===`, so passing object tokens makes this identity-based — an earlier loop left
// over from a restart, a remount (navigating away from the page and back), a hot
// reload, or a double-invoked effect sees a newer current token and bails, instead of
// stepping a second, desynced game world (you'd see enemies from one loop while the
// ship and lasers live in the other, so everything phases through).
export const loopIsCurrent = <T>(mine: T, current: T, stopped: boolean): boolean =>
  !stopped && mine === current

// Max sim steps run in a single animation frame. Bounds catch-up work, and — paired
// with the backlog drop in advanceClock — stops a backgrounded tab from fast-forwarding.
export const MAX_STEPS_PER_FRAME = 5

// Fixed-timestep clock. Folds the time elapsed since the last frame into the leftover
// accumulator and returns how many `stepMs` sim steps to run now, plus the carry-over
// accumulator. Runs at most MAX_STEPS_PER_FRAME per frame; if that cap is hit we're
// further behind than we can fairly catch up — almost always because the tab was
// backgrounded (the browser pauses rAF while hidden, then resumes with a huge elapsed
// delta) — so the remaining backlog is DROPPED and play resumes at real-time speed
// instead of speeding up. Negative/NaN elapsed (clock skew) contributes nothing.
export const advanceClock = (
  acc: number,
  elapsed: number,
  stepMs: number,
): {steps: number; acc: number} => {
  const total = acc + Math.max(elapsed, 0)
  const want = Math.floor(total / stepMs)
  if (want >= MAX_STEPS_PER_FRAME) return {steps: MAX_STEPS_PER_FRAME, acc: 0}
  return {steps: want, acc: total - want * stepMs}
}
